    // Initialize a vector to keep track of the number of times each index is multiplied by a value
    let mut count = vec![0; n];

    for query in queries {
        let li = query[0];
        let ri = query[1];
        let ki = query[2];
        let vi = query[3];

        let mut idx = li;
        while idx <= ri {
            count[idx] += 1;
            idx += ki;
        }
    }

    let mut result = 0;
    for i in 0..n {
        let mut val = nums[i];
        for _ in 0..count[i] {
            val = (val * vi) % mod_val;
        }
        result ^= val;
    }

    result
}
